import o from"node:net";describe("createServer and connect",()=>{it("should create a server and connect to it",s=>{let e=o.createServer();e.listen(()=>{let t=o.connect(e.address().port,()=>{t.end(()=>{e.close(s)})})})}),it("should handle data transfer between server and client",s=>{let e="Hello from client",t=o.createServer(r=>{r.on("data",n=>{expect(n.toString()).toEqual(e),r.write(n)})});t.listen(()=>{let r=o.connect(t.address().port,()=>{r.write(e),r.on("data",n=>{expect(n.toString()).toEqual(e),r.end(()=>{t.close(s)})})})})}),it("should handle data from server first",s=>{let e="Hello from client",t=o.createServer(r=>{r.write(e)});t.listen(()=>{let r=o.connect(t.address().port,()=>{r.on("data",n=>{expect(n.toString()).toEqual(e),r.end(()=>{t.close(s)})})})})})});describe("error handling",()=>{it("should handle connection error",s=>{let e=o.createServer();e.listen(0,()=>{let t=e.address().port;e.close(()=>{let r=o.connect(t,"127.0.0.1").on("error",n=>{expect(n).toBeInstanceOf(Error),r.destroy(),s()})})})}),it("should handle server destroy",s=>{let e=o.createServer(t=>{t.on("data",()=>{t.destroy()})});e.listen(()=>{let t=o.connect(e.address().port,()=>{t.write("hello")});t.on("close",()=>{t.end(),e.close(s)})})}),it("should handle client destroy",s=>{let e,t=new Promise(n=>{e=n}),r=o.createServer(async n=>{await t,setTimeout(()=>{n.write("hello",c=>{expect(c).toBeTruthy(),r.close(),s()})},5)});r.listen(()=>{let n=o.connect(r.address().port,()=>{n.destroy(),n.on("close",e)})})})});
